/**
 * US Common Core State Standards - English Language Arts (ELA)
 * Grades K-12
 *
 * Official Source: https://www.corestandards.org/ELA-Literacy/ (Public Domain)
 *
 * Notation System: US.CC.{grade}.ELA.{domain}.{number}
 * - Domain codes:
 *   K-8:
 *   - RL = Reading Literature
 *   - RI = Reading Informational Text
 *   - RF = Reading Foundational Skills (K-5 only)
 *   - W = Writing
 *   - SL = Speaking and Listening
 *   - L = Language
 *
 *   High School (9-12):
 *   - RL = Reading Literature (complex texts, literary analysis)
 *   - RI = Reading Informational Text (rhetorical analysis, seminal documents)
 *   - W = Writing (argumentative, research, narrative)
 *   - SL = Speaking and Listening (collaborative discussions, presentations)
 *   - L = Language (conventions, vocabulary, style)
 *
 * Note: Common Core organizes HS ELA in grade bands (9-10, 11-12). Standards
 * have been mapped to individual grades based on typical instructional sequence.
 */

export interface CommonCoreELAStandard {
  notation: string;
  domain: string;
  cluster: string;
  description: string;
}

export interface CommonCoreELAGrade {
  grade: number;
  gradeLabel: string;
  ageRangeMin: number;
  ageRangeMax: number;
  standards: CommonCoreELAStandard[];
}

export interface CommonCoreELACurriculum {
  code: string;
  name: string;
  country: string;
  version: string;
  sourceUrl: string;
  subject: string;
  grades: CommonCoreELAGrade[];
}

